mapper.select:
/*mapper.user.UserMapper.findUserCount */ SELECT count(*) AS count FROM users WHERE 1=1
AND role_code = #{roleCode}
AND created_at between STR_TO_DATE(CONCAT(#{oneMonthAgo},' 00:00:00'), '%Y-%m-%d %H:%i:%s') and STR_TO_DATE(CONCAT(#{today},' 23:59:59'), '%Y-%m-%d %H:%i:%s')

/*mapper.user.UserMapper.findUserList */ SELECT u.EMAIL AS email , u.NICKNAME AS nickname , u.PROVIDER_CODE AS providerCode , u.PROFILE_IMAGE_URL AS profileImageUrl , u.USER_STATUS_CODE AS userStatusCode , u.ROLE_CODE AS roleCode , u.TERMS_AGREED_YN AS termsAgreedYn , u.PRIVACY_AGREED_YN AS privacyAgreedYn , u.CREATED_AT AS createdAt , u.UPDATED_AT AS updatedAt , u.DELETED_AT AS deletedAt , u.LAST_LOGIN_AT AS lastLoginAt FROM users u WHERE 1=1
AND u.CREATED_AT < #{lastId}
ORDER BY u.CREATED_AT DESC LIMIT #{size}
